INSERT INTO apps (title, slug, developer, description, category_id, type, icon_url, banner_url, screenshots, version, file_size, rating, downloads, download_url, checksum, is_featured, is_trending, is_recent, is_recommended) VALUES
('Shadow Combat 5', 'shadow-combat-5', 'GameForge Studios', 'An intense action-packed combat game with stunning graphics and immersive gameplay. Battle through 50+ levels with customizable weapons and gear.', (SELECT id FROM categories WHERE slug='action'), 'game', 'https://images.pexels.com/photos/2115216/pexels-photo-2115216.jpeg?auto=compress&cs=tinysrgb&w=200&h=200&fit=crop', 'https://images.pexels.com/photos/2115216/pexels-photo-2115216.jpeg?auto=compress&cs=tinysrgb&w=1200&h=500&fit=crop', '["https://images.pexels.com/photos/2115216/pexels-photo-2115216.jpeg?auto=compress&cs=tinysrgb&w=800","https://images.pexels.com/photos/3165335/pexels-photo-3165335.jpeg?auto=compress&cs=tinysrgb&w=800","https://images.pexels.com/photos/903631/pexels-photo-903631.jpeg?auto=compress&cs=tinysrgb&w=800"]', '5.2.1', '1.2 GB', 4.8, 12500000, 'private://apk/shadow-combat-5-v5.2.1.apk', 'a3f5e8c1b2d4f6a8e9c7d1b3f5a7e9c1d2b4f6a8e0c3d5b7f9a1e3c5d7b9f1a2c', true, true, false, true),
('Neon Racer X', 'neon-racer-x', 'Velocity Games', 'High-octane racing through neon-lit city streets. Customize your ride, compete in tournaments, and dominate the leaderboards.', (SELECT id FROM categories WHERE slug='racing'), 'game', 'https://images.pexels.com/photos/3806248/pexels-photo-3806248.jpeg?auto=compress&cs=tinysrgb&w=200&h=200&fit=crop', 'https://images.pexels.com/photos/3806248/pexels-photo-3806248.jpeg?auto=compress&cs=tinysrgb&w=1200&h=500&fit=crop', '["https://images.pexels.com/photos/3806248/pexels-photo-3806248.jpeg?auto=compress&cs=tinysrgb&w=800","https://images.pexels.com/photos/3770114/pexels-photo-3770114.jpeg?auto=compress&cs=tinysrgb&w=800","https://images.pexels.com/photos/373544/pexels-photo-373544.jpeg?auto=compress&cs=tinysrgb&w=800"]', '3.7.0', '850 MB', 4.6, 8200000, 'private://apk/neon-racer-x-v3.7.0.apk', 'b4e6f9d2c3a5e7b1d8f0a2c4e6b8d1f3a5e7c9b1d3f5a7e9c1b3d5f7a9e1c3d5', true, true, true, false),
('Pixel Dungeon Quest', 'pixel-dungeon-quest', 'RetroPixel Studio', 'A retro-style dungeon crawler with procedurally generated levels, pixel art aesthetics, and challenging boss battles.', (SELECT id FROM categories WHERE slug='adventure'), 'game', 'https://images.pexels.com/photos/2115256/pexels-photo-2115256.jpeg?auto=compress&cs=tinysrgb&w=200&h=200&fit=crop', NULL, '["https://images.pexels.com/photos/2115256/pexels-photo-2115256.jpeg?auto=compress&cs=tinysrgb&w=800","https://images.pexels.com/photos/3165335/pexels-photo-3165335.jpeg?auto=compress&cs=tinysrgb&w=800"]', '2.1.4', '120 MB', 4.7, 3400000, 'private://apk/pixel-dungeon-quest-v2.1.4.apk', 'c5f7a1e3d6b8f2c4a6e8d1b3f5a7e9c1d2b4f6a8e0c3d5b7f9a1e3c5d7b9f1a2', false, false, true, true),
('Galaxy Defender', 'galaxy-defender', 'Cosmic Interactive', 'Defend the galaxy from alien invasion in this epic space shooter. Upgrade your ship, unlock powerful weapons, and save humanity.', (SELECT id FROM categories WHERE slug='arcade'), 'game', 'https://images.pexels.com/photos/2150/pexels-photo-2150.jpeg?auto=compress&cs=tinysrgb&w=200&h=200&fit=crop', 'https://images.pexels.com/photos/2150/pexels-photo-2150.jpeg?auto=compress&cs=tinysrgb&w=1200&h=500&fit=crop', '["https://images.pexels.com/photos/2150/pexels-photo-2150.jpeg?auto=compress&cs=tinysrgb&w=800","https://images.pexels.com/photos/2387873/pexels-photo-2387873.jpeg?auto=compress&cs=tinysrgb&w=800"]', '4.0.2', '95 MB', 4.5, 5600000, 'private://apk/galaxy-defender-v4.0.2.apk', 'd6a8b2f4e7c1d3f5a7e9b1d3f5a7e9c1d2b4f6a8e0c3d5b7f9a1e3c5d7b9f1a', true, false, false, true),
('Empire Wars', 'empire-wars', 'Throne Studios', 'Build your empire, forge alliances, and conquer rival kingdoms in this deep strategy game with real-time battles.', (SELECT id FROM categories WHERE slug='strategy'), 'game', 'https://images.pexels.com/photos/2698925/pexels-photo-2698925.jpeg?auto=compress&cs=tinysrgb&w=200&h=200&fit=crop', NULL, '["https://images.pexels.com/photos/2698925/pexels-photo-2698925.jpeg?auto=compress&cs=tinysrgb&w=800","https://images.pexels.com/photos/3165335/pexels-photo-3165335.jpeg?auto=compress&cs=tinysrgb&w=800"]', '7.3.1', '1.5 GB', 4.4, 9800000, 'private://apk/empire-wars-v7.3.1.apk', 'e7b9c3d5f8a2e4c6d8b0f2a4c6e8b1d3f5a7e9c1d2b4f6a8e0c3d5b7f9a1e3c', false, true, false, true),
('Zombie Survival FPS', 'zombie-survival-fps', 'DeadPixel Games', 'Survive the zombie apocalypse in this intense first-person shooter. Scavenge for resources, build defenses, and fight to stay alive.', (SELECT id FROM categories WHERE slug='action'), 'game', 'https://images.pexels.com/photos/2115256/pexels-photo-2115256.jpeg?auto=compress&cs=tinysrgb&w=200&h=200&fit=crop', 'https://images.pexels.com/photos/2115256/pexels-photo-2115256.jpeg?auto=compress&cs=tinysrgb&w=1200&h=500&fit=crop', '["https://images.pexels.com/photos/2115256/pexels-photo-2115256.jpeg?auto=compress&cs=tinysrgb&w=800","https://images.pexels.com/photos/3165335/pexels-photo-3165335.jpeg?auto=compress&cs=tinysrgb&w=800","https://images.pexels.com/photos/903631/pexels-photo-903631.jpeg?auto=compress&cs=tinysrgb&w=800"]', '1.8.5', '1.1 GB', 4.3, 4200000, 'private://apk/zombie-survival-fps-v1.8.5.apk', 'f8c0d4e6a9b3f5e7c9d1b3f5a7e9c1d2b4f6a8e0c3d5b7f9a1e3c5d7b9f1a2c', true, true, true, false),
('Mega Block Builder', 'mega-block-builder', 'CreativeCraft Studio', 'Build, explore, and create in this open-world sandbox game. Unlimited blocks, creative mode, and multiplayer support.', (SELECT id FROM categories WHERE slug='adventure'), 'game', 'https://images.pexels.com/photos/2115216/pexels-photo-2115216.jpeg?auto=compress&cs=tinysrgb&w=200&h=200&fit=crop', NULL, '["https://images.pexels.com/photos/2115216/pexels-photo-2115216.jpeg?auto=compress&cs=tinysrgb&w=800","https://images.pexels.com/photos/3165335/pexels-photo-3165335.jpeg?auto=compress&cs=tinysrgb&w=800"]', '1.20.1', '180 MB', 4.9, 25000000, 'private://apk/mega-block-builder-v1.20.1.apk', 'a9d1e5c7b3f5a7e9c1d3f5a7e9c1d2b4f6a8e0c3d5b7f9a1e3c5d7b9f1a2c4', false, false, true, true),
('Turbo Drift Masters', 'turbo-drift-masters', 'Apex Racing', 'Master the art of drifting in this realistic racing simulator. 100+ cars, 50+ tracks, and online multiplayer competitions.', (SELECT id FROM categories WHERE slug='racing'), 'game', 'https://images.pexels.com/photos/3770114/pexels-photo-3770114.jpeg?auto=compress&cs=tinysrgb&w=200&h=200&fit=crop', NULL, '["https://images.pexels.com/photos/3770114/pexels-photo-3770114.jpeg?auto=compress&cs=tinysrgb&w=800","https://images.pexels.com/photos/373544/pexels-photo-373544.jpeg?auto=compress&cs=tinysrgb&w=800"]', '2.5.0', '780 MB', 4.2, 3100000, 'private://apk/turbo-drift-masters-v2.5.0.apk', 'b0e2f6a8c4d6b8f0a2c4e6b8d1f3a5e7c9b1d3f5a7e9c1b3d5f7a9e1c3d5b7', false, false, false, false),
('Tower Defense Legends', 'tower-defense-legends', 'Strategy Forge', 'Build towers, train troops, and defend your kingdom against waves of enemies. 30+ tower types and 100+ levels.', (SELECT id FROM categories WHERE slug='strategy'), 'game', 'https://images.pexels.com/photos/903631/pexels-photo-903631.jpeg?auto=compress&cs=tinysrgb&w=200&h=200&fit=crop', NULL, '["https://images.pexels.com/photos/903631/pexels-photo-903631.jpeg?auto=compress&cs=tinysrgb&w=800","https://images.pexels.com/photos/3165335/pexels-photo-3165335.jpeg?auto=compress&cs=tinysrgb&w=800"]', '3.2.0', '75 MB', 4.6, 6700000, 'private://apk/tower-defense-legends-v3.2.0.apk', 'c1f3a7b9d5e7c1d3f5a7e9c1d2b4f6a8e0c3d5b7f9a1e3c5d7b9f1a2c4e6b8', false, true, true, false),
('Arcade Brick Breaker', 'arcade-brick-breaker', 'ClassicGames Inc', 'A modern take on the classic brick breaker. 200+ levels, power-ups, and boss battles with vibrant neon visuals.', (SELECT id FROM categories WHERE slug='arcade'), 'game', 'https://images.pexels.com/photos/2387873/pexels-photo-2387873.jpeg?auto=compress&cs=tinysrgb&w=200&h=200&fit=crop', NULL, '["https://images.pexels.com/photos/2387873/pexels-photo-2387873.jpeg?auto=compress&cs=tinysrgb&w=800"]', '1.5.2', '45 MB', 4.1, 2200000, 'private://apk/arcade-brick-breaker-v1.5.2.apk', 'd2a4b8c0e6d8f2a4c6e8b1d3f5a7e9c1d2b4f6a8e0c3d5b7f9a1e3c5d7b9f1', false, false, false, false),
('Fantasy RPG Online', 'fantasy-rpg-online', 'Mythic Worlds', 'Embark on an epic MMORPG adventure. Choose your class, explore vast open worlds, and battle dragons with friends.', (SELECT id FROM categories WHERE slug='adventure'), 'game', 'https://images.pexels.com/photos/3165335/pexels-photo-3165335.jpeg?auto=compress&cs=tinysrgb&w=200&h=200&fit=crop', 'https://images.pexels.com/photos/3165335/pexels-photo-3165335.jpeg?auto=compress&cs=tinysrgb&w=1200&h=500&fit=crop', '["https://images.pexels.com/photos/3165335/pexels-photo-3165335.jpeg?auto=compress&cs=tinysrgb&w=800","https://images.pexels.com/photos/903631/pexels-photo-903631.jpeg?auto=compress&cs=tinysrgb&w=800"]', '6.0.0', '2.1 GB', 4.7, 15000000, 'private://apk/fantasy-rpg-online-v6.0.0.apk', 'e3b5c9d1f7a3e5c7d9b1f3a5e7c9b1d3f5a7e9c1d2b4f6a8e0c3d5b7f9a1e3', true, true, false, true),
('Ninja Shadow Strike', 'ninja-shadow-strike', 'ShadowBlade Games', 'Become a legendary ninja in this stealth-action game. Parkour, assassinations, and an open-world feudal Japan setting.', (SELECT id FROM categories WHERE slug='action'), 'game', 'https://images.pexels.com/photos/2698925/pexels-photo-2698925.jpeg?auto=compress&cs=tinysrgb&w=200&h=200&fit=crop', NULL, '["https://images.pexels.com/photos/2698925/pexels-photo-2698925.jpeg?auto=compress&cs=tinysrgb&w=800","https://images.pexels.com/photos/3165335/pexels-photo-3165335.jpeg?auto=compress&cs=tinysrgb&w=800"]', '2.3.1', '920 MB', 4.5, 5300000, 'private://apk/ninja-shadow-strike-v2.3.1.apk', 'f4c6d0e2a8b4f6a8e0c2d4b6f8a1d3f5a7e9c1d2b4f6a8e0c3d5b7f9a1e3c5', false, false, true, false)
INSERT INTO apps (title, slug, developer, description, category_id, type, icon_url, banner_url, screenshots, version, file_size, rating, downloads, download_url, checksum, is_featured, is_trending, is_recent, is_recommended) VALUES
('Pro Cleaner Plus', 'pro-cleaner-plus', 'OptiTools', 'Boost your device performance with one tap. Clean junk files, manage storage, optimize RAM, and extend battery life.', (SELECT id FROM categories WHERE slug='tools'), 'app', 'https://images.pexels.com/photos/1181244/pexels-photo-1181244.jpeg?auto=compress&cs=tinysrgb&w=200&h=200&fit=crop', 'https://images.pexels.com/photos/1181244/pexels-photo-1181244.jpeg?auto=compress&cs=tinysrgb&w=1200&h=500&fit=crop', '["https://images.pexels.com/photos/1181244/pexels-photo-1181244.jpeg?auto=compress&cs=tinysrgb&w=800","https://images.pexels.com/photos/1181467/pexels-photo-1181467.jpeg?auto=compress&cs=tinysrgb&w=800"]', '4.1.0', '28 MB', 4.4, 18000000, 'private://apk/pro-cleaner-plus-v4.1.0.apk', 'a5e7c1d3b5f7a9c1e3d5b7f9a1e3c5d7b9f1a3c5e7b9d1f3a5c7e9b1d3f5a7', true, true, false, true),
('TaskFlow Pro', 'taskflow-pro', 'ProductivityHub', 'Organize your life with powerful task management. Projects, subtasks, reminders, calendar sync, and team collaboration.', (SELECT id FROM categories WHERE slug='productivity'), 'app', 'https://images.pexels.com/photos/1181467/pexels-photo-1181467.jpeg?auto=compress&cs=tinysrgb&w=200&h=200&fit=crop', 'https://images.pexels.com/photos/1181467/pexels-photo-1181467.jpeg?auto=compress&cs=tinysrgb&w=1200&h=500&fit=crop', '["https://images.pexels.com/photos/1181467/pexels-photo-1181467.jpeg?auto=compress&cs=tinysrgb&w=800","https://images.pexels.com/photos/1181244/pexels-photo-1181244.jpeg?auto=compress&cs=tinysrgb&w=800"]', '5.0.3', '52 MB', 4.8, 9500000, 'private://apk/taskflow-pro-v5.0.3.apk', 'b6f8d2e4c6a8b0d2f4a6c8e0b2d4f6a8e0b2d4f6a8e0b2d4f6a8e0b2d4f6a8', true, true, true, false),
('ChatWave Messenger', 'chatwave-messenger', 'ConnectSocial', 'Secure messaging with end-to-end encryption, voice/video calls, group chats, and file sharing. No ads, no tracking.', (SELECT id FROM categories WHERE slug='social'), 'app', 'https://images.pexels.com/photos/1181244/pexels-photo-1181244.jpeg?auto=compress&cs=tinysrgb&w=200&h=200&fit=crop', NULL, '["https://images.pexels.com/photos/1181244/pexels-photo-1181244.jpeg?auto=compress&cs=tinysrgb&w=800","https://images.pexels.com/photos/1181467/pexels-photo-1181467.jpeg?auto=compress&cs=tinysrgb&w=800"]', '8.2.1', '65 MB', 4.6, 22000000, 'private://apk/chatwave-messenger-v8.2.1.apk', 'c7a9e3f5d8b1f3a5c7e9b1d3f5a7e9c1d2b4f6a8e0c3d5b7f9a1e3c5d7b9f1', false, false, true, true),
('StreamFlix Player', 'streamflix-player', 'MediaStream Inc', 'Play any video format with this powerful media player. Subtitles, casting, playlist support, and 4K playback.', (SELECT id FROM categories WHERE slug='entertainment'), 'app', 'https://images.pexels.com/photos/325153/pexels-photo-325153.jpeg?auto=compress&cs=tinysrgb&w=200&h=200&fit=crop', 'https://images.pexels.com/photos/325153/pexels-photo-325153.jpeg?auto=compress&cs=tinysrgb&w=1200&h=500&fit=crop', '["https://images.pexels.com/photos/325153/pexels-photo-325153.jpeg?auto=compress&cs=tinysrgb&w=800","https://images.pexels.com/photos/1181467/pexels-photo-1181467.jpeg?auto=compress&cs=tinysrgb&w=800"]', '3.5.0', '42 MB', 4.5, 7800000, 'private://apk/streamflix-player-v3.5.0.apk', 'd8b0f4a6e9c2d4f6a8e0b2d4f6a8e0b2d4f6a8e0b2d4f6a8e0b2d4f6a8e0', true, false, false, true),
('LearnCode Academy', 'learncode-academy', 'EduTech Solutions', 'Learn programming with interactive lessons. Python, JavaScript, Java, C++ — 500+ exercises with real-time feedback.', (SELECT id FROM categories WHERE slug='education'), 'app', 'https://images.pexels.com/photos/1181244/pexels-photo-1181244.jpeg?auto=compress&cs=tinysrgb&w=200&h=200&fit=crop', NULL, '["https://images.pexels.com/photos/1181244/pexels-photo-1181244.jpeg?auto=compress&cs=tinysrgb&w=800","https://images.pexels.com/photos/1181467/pexels-photo-1181467.jpeg?auto=compress&cs=tinysrgb&w=800"]', '2.8.0', '58 MB', 4.9, 4300000, 'private://apk/learncode-academy-v2.8.0.apk', 'e9c1f5b7a0d3e5c7b9d1f3a5e7c9b1d3f5a7e9c1d2b4f6a8e0c3d5b7f9a1e3', false, true, true, true),
('VPN Shield Pro', 'vpn-shield-pro', 'SecureNet Labs', 'Protect your privacy with military-grade encryption. 100+ server locations, no logs policy, and unlimited bandwidth.', (SELECT id FROM categories WHERE slug='tools'), 'app', 'https://images.pexels.com/photos/1181467/pexels-photo-1181467.jpeg?auto=compress&cs=tinysrgb&w=200&h=200&fit=crop', 'https://images.pexels.com/photos/1181467/pexels-photo-1181467.jpeg?auto=compress&cs=tinysrgb&w=1200&h=500&fit=crop', '["https://images.pexels.com/photos/1181467/pexels-photo-1181467.jpeg?auto=compress&cs=tinysrgb&w=800","https://images.pexels.com/photos/1181244/pexels-photo-1181244.jpeg?auto=compress&cs=tinysrgb&w=800"]', '6.1.0', '35 MB', 4.7, 12000000, 'private://apk/vpn-shield-pro-v6.1.0.apk', 'f0d2a6c8b1e3f5a7c9d1f3a5e7c9b1d3f5a7e9c1d2b4f6a8e0c3d5b7f9a1e3', true, true, false, false),
('NoteMaster Sync', 'notemaster-sync', 'ProductivityHub', 'Capture ideas with rich text notes, handwriting, audio recordings, and cloud sync across all your devices.', (SELECT id FROM categories WHERE slug='productivity'), 'app', 'https://images.pexels.com/photos/325153/pexels-photo-325153.jpeg?auto=compress&cs=tinysrgb&w=200&h=200&fit=crop', NULL, '["https://images.pexels.com/photos/325153/pexels-photo-325153.jpeg?auto=compress&cs=tinysrgb&w=800","https://images.pexels.com/photos/1181467/pexels-photo-1181467.jpeg?auto=compress&cs=tinysrgb&w=800"]', '4.3.2', '48 MB', 4.6, 6100000, 'private://apk/notemaster-sync-v4.3.2.apk', 'a1e3c7d9b2f4a6c8e0b2d4f6a8e0b2d4f6a8e0b2d4f6a8e0b2d4f6a8e0b2d4', false, false, false, true),
('SocialGram Photo', 'socialgram-photo', 'ConnectSocial', 'Share photos, apply filters, and connect with friends. Stories, reels, direct messages, and creative editing tools.', (SELECT id FROM categories WHERE slug='social'), 'app', 'https://images.pexels.com/photos/1181244/pexels-photo-1181244.jpeg?auto=compress&cs=tinysrgb&w=200&h=200&fit=crop', 'https://images.pexels.com/photos/1181244/pexels-photo-1181244.jpeg?auto=compress&cs=tinysrgb&w=1200&h=500&fit=crop', '["https://images.pexels.com/photos/1181244/pexels-photo-1181244.jpeg?auto=compress&cs=tinysrgb&w=800","https://images.pexels.com/photos/325153/pexels-photo-325153.jpeg?auto=compress&cs=tinysrgb&w=800"]', '12.0.1', '72 MB', 4.3, 35000000, 'private://apk/socialgram-photo-v12.0.1.apk', 'b2f4d8e0c3a5b7c9d1f3a5e7c9b1d3f5a7e9c1d2b4f6a8e0c3d5b7f9a1e3c5', true, true, true, false),
('MusicFlow Studio', 'musicflow-studio', 'AudioLab Productions', 'Create music on the go. 100+ instruments, beat maker, multi-track recording, and professional effects.', (SELECT id FROM categories WHERE slug='entertainment'), 'app', 'https://images.pexels.com/photos/325153/pexels-photo-325153.jpeg?auto=compress&cs=tinysrgb&w=200&h=200&fit=crop', NULL, '["https://images.pexels.com/photos/325153/pexels-photo-325153.jpeg?auto=compress&cs=tinysrgb&w=800","https://images.pexels.com/photos/1181467/pexels-photo-1181467.jpeg?auto=compress&cs=tinysrgb&w=800"]', '5.4.0', '88 MB', 4.4, 2900000, 'private://apk/musicflow-studio-v5.4.0.apk', 'c3a5e7c9d4b6f8a0c2d4f6a8e0b2d4f6a8e0b2d4f6a8e0b2d4f6a8e0b2d4f6', false, false, false, false),
